import{_ as t,c as e,o as r,a4 as a}from"./chunks/framework.HaEZziQ1.js";const u=JSON.parse('{"title":"学习资源和方法","description":"","frontmatter":{},"headers":[],"relativePath":"order/学习资源和方法.md","filePath":"order/学习资源和方法.md","lastUpdated":1709668918000}'),o={name:"order/学习资源和方法.md"},d=a('<h1 id="学习资源和方法" tabindex="-1">学习资源和方法 <a class="header-anchor" href="#学习资源和方法" aria-label="Permalink to &quot;学习资源和方法&quot;">​</a></h1><p><strong>前端技术排名网站</strong>：<a href="https://risingstars.js.org/2022/zh" target="_blank" rel="noreferrer">https://risingstars.js.org/2022/zh</a></p><p><a href="https://juejin.cn/post/7137294579346178084" target="_blank" rel="noreferrer">上海疫情后一个前端的面试心路历程 - 掘金 (juejin.cn)</a></p><p><strong>随着用户的增多，项目的性能与持续优化就变成的异常重要</strong>：</p><p><code>一百用户与一百万用户的网站有着本质区别</code></p><p>任何细节都变得更为重要，一个最常见的例子：</p><p>商城项目的长列表渲染优化，长列表渲染的性能效率与用户体验成正比</p><p>用到的技术包括：分页+虚拟滚动、图片懒加载、图片的动态裁剪等等</p><p><code>在挑战中成长</code></p><p>开始第一次负责大型网站的系统架构、性能分析、网站优化、网站监控等方面</p><p><code>开始慢慢理解前端，开始注重用户体验，逐渐学会承受压力</code></p><h2 id="瓶颈期" tabindex="-1">瓶颈期 <a class="header-anchor" href="#瓶颈期" aria-label="Permalink to &quot;瓶颈期&quot;">​</a></h2><p><strong>目标照亮前行的路</strong>：</p><p>我不是一个自制力很强的人，需要给每个阶段都设置一个清晰的目标，否则就会掉队</p><p><code>一个风筝，必须有一根绳子牵着，大厂就是这根绳子</code></p><p><strong>备战面试</strong>：</p><p>前后准备了多少个月个月时间，把制定的学习计划具体到天</p><p><strong>没有严格的时间限制，学习进度和效果就会大打折扣</strong>：</p><table><thead><tr><th>时间</th><th>任务</th></tr></thead><tbody><tr><td>2个月</td><td>系统性学习了前端的基础知识，浏览器运行机制，重点练习手写js题</td></tr><tr><td>2个月</td><td>练习算法，对应数据结构与题型分类练习！刷了一百多道leetcode题</td></tr><tr><td>1个月</td><td>利用performanc和Lighthouse分析工具，结合web vitals关键指标计算方法，制定页面的整体优化方案</td></tr><tr><td>1个月</td><td>搭建自己的脚手架，创建pc、h5项目模板等，手写webpack、手写babel插件等</td></tr><tr><td>1个月</td><td>复习了node知识，学习了网络协议、网络安全与攻击防御方法等</td></tr><tr><td>1个月</td><td>复习vue与react源码，学会如何手写一个简单的vue</td></tr></tbody></table><p><strong>对算法的误解</strong>：</p><p>之前我对算法的理解，仅仅是为了应付大厂的面试</p><p>在两个月的算法练习中，我第一次体会到：<code>编程不仅仅是技术，还是艺术</code></p><p>比如简单的循环，就可以解决很复杂的数学问题</p><blockquote><p>算法对前端来说并不是非常重要，但却是一个优秀前端工程师的必备技能，对于提升编码能力有着举重若轻的作用</p></blockquote><h3 id="简历" tabindex="-1">简历 <a class="header-anchor" href="#简历" aria-label="Permalink to &quot;简历&quot;">​</a></h3><ul><li>精通HTML+CSS+JavaScript等前端基础技术,根据设计图还原视觉性设计,兼容各大主流游览器,也能够进行移动端的开发;</li><li>精通Vue以及相关全家桶,可高质量且快速地完成项目;</li><li>熟悉webpack，git等前端工程化内容,具有前端性能优化、前端工程构建相关经验;</li><li>熟悉Node.js、TypeScript、Koa、React、MySql；</li><li>理解数据结构、计算机网络、规范化、微前端、微信小程序服务商模式</li><li>理解前后端分离设计和模块化设计思想, 熟悉常用设计模式,能够独立进行组件开发;</li></ul>',26),p=[d];function s(n,c,i,l,h,_){return r(),e("div",null,p)}const b=t(o,[["render",s]]);export{u as __pageData,b as default};
